import { createRouter, createWebHistory, type RouteRecordRaw } from 'vue-router';
import AppShell from '../layouts/AppShell.vue';
import LoginPage from '../pages/LoginPage.vue';
import MemberHomePage from '../pages/MemberHomePage.vue';
import GroupLeaderHomePage from '../pages/GroupLeaderHomePage.vue';
import ReviewerHomePage from '../pages/ReviewerHomePage.vue';
import FinanceClerkHomePage from '../pages/FinanceClerkHomePage.vue';
import AdministratorHomePage from '../pages/AdministratorHomePage.vue';
import ForbiddenPage from '../pages/ForbiddenPage.vue';
import { useAuthStore } from '../stores/authStore';
import type { RoleName } from '../types/auth';
import { roleHomePaths } from '../constants/roles';

const routes: RouteRecordRaw[] = [
  {
    path: '/login',
    name: 'login',
    component: LoginPage,
    meta: { public: true }
  },
  {
    path: '/',
    component: AppShell,
    children: [
      {
        path: 'home/member',
        component: MemberHomePage,
        meta: { roles: ['MEMBER'] }
      },
      {
        path: 'home/group-leader',
        component: GroupLeaderHomePage,
        meta: { roles: ['GROUP_LEADER'] }
      },
      {
        path: 'home/reviewer',
        component: ReviewerHomePage,
        meta: { roles: ['REVIEWER'] }
      },
      {
        path: 'home/finance-clerk',
        component: FinanceClerkHomePage,
        meta: { roles: ['FINANCE_CLERK'] }
      },
      {
        path: 'home/administrator',
        component: AdministratorHomePage,
        meta: { roles: ['ADMINISTRATOR'] }
      }
    ]
  },
  {
    path: '/forbidden',
    component: ForbiddenPage
  }
];

export const router = createRouter({
  history: createWebHistory(),
  routes
});

router.beforeEach(async (to) => {
  const authStore = useAuthStore();

  if (!authStore.initialized) {
    await authStore.initialize();
  }

  const requiresPublic = Boolean(to.meta.public);
  if (requiresPublic) {
    if (authStore.isAuthenticated && to.path === '/login') {
      const firstRole = authStore.user?.roles[0];
      if (firstRole) {
        return roleHomePaths[firstRole];
      }
    }
    return true;
  }

  if (!authStore.isAuthenticated) {
    return '/login';
  }

  const requiredRoles = (to.meta.roles as RoleName[] | undefined) ?? [];
  if (requiredRoles.length === 0) {
    return true;
  }

  const allowed = requiredRoles.some((role) => authStore.roles.includes(role));
  if (!allowed) {
    return '/forbidden';
  }

  return true;
});
