            {{ listing.isFavoritePickupPoint ? 'Unfavorite Pickup Point' : 'Favorite Pickup Point' }}
          </button>
          <button @click="toggleFavorite('LEADER', listing.leaderUserId)">
            {{ listing.isFavoriteLeader ? 'Unfavorite Leader' : 'Favorite Leader' }}
          </button>
