<script setup lang="ts">
import { computed, onMounted, ref } from 'vue';
import { useRoute, useRouter } from 'vue-router';
import { commerceApi } from '../api/commerceApi';
import type { ListingItem } from '../types/commerce';

const route = useRoute();
const router = useRouter();

const loading = ref(false);
const error = ref('');
const listings = ref<ListingItem[]>([]);
const page = ref(1);
const pageSize = ref(10);
const total = ref(0);
const search = ref('');
const sortBy = ref<'title' | 'price' | 'recent'>('recent');
const sortDir = ref<'asc' | 'desc'>('desc');

const cycleId = computed(() => Number(route.query.cycleId ?? 0));
const cycleIdLabel = computed(() => (cycleId.value > 0 ? String(cycleId.value) : 'missing'));
const maxPage = computed(() => Math.max(1, Math.ceil(total.value / pageSize.value)));

const fetchListings = async () => {
  if (!cycleId.value) {
    error.value = 'Missing cycleId query parameter.';
    listings.value = [];
    return;
  }

  loading.value = true;
  error.value = '';
  try {
    const response = await commerceApi.getListings({
      cycleId: cycleId.value,
      page: page.value,
      pageSize: pageSize.value,
      search: search.value,
      sortBy: sortBy.value,
      sortDir: sortDir.value
    });

    listings.value = response.data;
    total.value = response.total;
  } catch (err) {
    error.value = err instanceof Error ? err.message : 'Failed to load listings.';
    listings.value = [];
    total.value = 0;
  } finally {
    loading.value = false;
  }
};

const toggleFavorite = async (type: 'PICKUP_POINT' | 'LEADER', targetId: number) => {
  try {
    await commerceApi.toggleFavorite({ type, targetId });
    await fetchListings();
  } catch (err) {
    error.value = err instanceof Error ? err.message : 'Failed to toggle favorite.';
  }
};

const goToPickupPoint = async (pickupPointId: number) => {
  await router.push({ name: 'pickup-point-detail', params: { id: String(pickupPointId) } });
};

const prevPage = async () => {
  if (page.value > 1) {
    page.value -= 1;
    await fetchListings();
  }
};

const nextPage = async () => {
  if (page.value < maxPage.value) {
    page.value += 1;
    await fetchListings();
  }
};

onMounted(fetchListings);
</script>
