        <p><strong>${{ listing.basePrice }}</strong> / {{ listing.unitLabel }}</p>
        <p class="small-text">Available: {{ listing.availableQuantity - listing.reservedQuantity }}</p>
        <p class="small-text">Pickup Point: {{ listing.pickupPointName }}</p>
