    mockedRepo.listPickupWindowsByPoint.mockResolvedValueOnce([
      {
        id: 1,
        pickup_point_id: 2,
        window_date: '2026-03-26',
        start_time: '09:00:00',
        end_time: '11:00:00',
        capacity_total: 50,
        reserved_slots: 49
      }
