        title: 'Kale',
        unitPrice: 5,
        availableQuantity: 20,
        reservedQuantity: 0
      }
    ]);
    repo.getActivePricingRuleVersions.mockResolvedValue([]);
    repo.getPickupWindowCapacity.mockResolvedValue({
      id: 5,
      pickupPointId: 2,
      windowDate: '2026-03-27',
      startTime: '09:00:00',
      endTime: '11:00:00',
      capacityTotal: 10,
      reservedSlots: 3
