  const pageSize = 20;
  const offset = (params.page - 1) * pageSize;

  const [countRows] = await dbPool.query<{ total: number }[]>(
    `SELECT COUNT(*) AS total
     FROM comments
     WHERE discussion_id = ?`,
    [params.discussionId]
  );

  const [rows] = await dbPool.query<
    {
      id: number;
