      userId = existingUsers[0].id;
      await conn.query('UPDATE users SET password_hash = ?, is_active = 1 WHERE id = ?', [
        params.passwordHash,
        userId
      ]);
    }

    const [roleRows] = await conn.query<{ id: number }[]>(
      'SELECT id FROM roles WHERE name = ? LIMIT 1',
      [params.role]
    );

