import fs from 'fs/promises';
import path from 'path';
import { dbPool } from './pool';

type Direction = 'up' | 'down';

const migrationsDir = path.resolve(__dirname, 'migrations');

const ensureMigrationsTable = async (): Promise<void> => {
  const initialSql = await fs.readFile(
    path.join(migrationsDir, '0001_create_migrations_table.sql'),
    'utf8'
  );
  await dbPool.query(initialSql);
};

const getAppliedMigrations = async (): Promise<Set<string>> => {
  const [rows] = await dbPool.query<{ name: string }[]>('SELECT name FROM migrations');
  return new Set(rows.map((row: { name: string }) => row.name));
};

const runUp = async (): Promise<void> => {
  await ensureMigrationsTable();

  const files = (await fs.readdir(migrationsDir))
    .filter((file) => file.endsWith('.sql') && !file.endsWith('.down.sql'))
    .sort();

  const applied = await getAppliedMigrations();

  for (const file of files) {
    if (applied.has(file)) {
      continue;
    }

    const sql = await fs.readFile(path.join(migrationsDir, file), 'utf8');
    const conn = await dbPool.getConnection();
    try {
      await conn.beginTransaction();
      await conn.query(sql);
      await conn.query('INSERT INTO migrations (name) VALUES (?)', [file]);
      await conn.commit();
      console.log(`Applied migration: ${file}`);
    } catch (error) {
      await conn.rollback();
      throw error;
    } finally {
      conn.release();
    }
  }
};

const runDown = async (): Promise<void> => {
  await ensureMigrationsTable();

  const [rows] = await dbPool.query<{ name: string }[]>(
    'SELECT name FROM migrations ORDER BY id DESC LIMIT 1'
  );

  if (rows.length === 0) {
    console.log('No applied migrations to roll back.');
    return;
  }

  const lastMigration = rows[0].name;

  if (lastMigration === '0001_create_migrations_table.sql') {
    await dbPool.query('DELETE FROM migrations WHERE name = ?', [lastMigration]);
    console.log('Removed base migrations marker.');
    return;
  }

  const downFile = `${lastMigration.replace(/\.sql$/, '')}.down.sql`;
  const downPath = path.join(migrationsDir, downFile);
  const sql = await fs.readFile(downPath, 'utf8');

  const conn = await dbPool.getConnection();
  try {
    await conn.beginTransaction();
    await conn.query(sql);
    await conn.query('DELETE FROM migrations WHERE name = ?', [lastMigration]);
    await conn.commit();
    console.log(`Rolled back migration: ${lastMigration}`);
  } catch (error) {
    await conn.rollback();
    throw error;
  } finally {
    conn.release();
  }
};

const main = async (): Promise<void> => {
  const direction = (process.argv[2] ?? 'up') as Direction;
  if (direction === 'down') {
    await runDown();
  } else {
    await runUp();
  }
  await dbPool.end();
};

main().catch(async (error) => {
  console.error(error);
  await dbPool.end();
  process.exit(1);
});

